<!doctype html><html><head><meta charset="utf-8"><style>body{font-family:DejaVu Sans,sans-serif;color:#17202a;font-size:12px}h1{font-size:22px;margin:0}.muted{color:#667085}.header{border-bottom:2px solid #111827;padding-bottom:16px;margin-bottom:18px}.grid{width:100%;border-collapse:collapse}.grid td{width:50%;padding:4px 0}.table{width:100%;border-collapse:collapse;margin-top:18px}.table th,.table td{padding:8px;border:1px solid #d0d5dd;text-align:left}.table th{background:#f2f4f7}.amount{text-align:right!important}.total{font-weight:bold;background:#ecfdf3}.footer{margin-top:28px;border-top:1px solid #d0d5dd;padding-top:10px}</style></head><body>
<div class="header"><h1>{{ $item->employee->company?->name ?? 'HRM System' }}</h1><div class="muted">Salary payslip · {{ $item->run->name }}</div></div>
<table class="grid"><tr><td><strong>Employee</strong><br>{{ $item->employee->user->name }}</td><td><strong>Employee ID</strong><br>{{ $item->employee->user->employee_id }}</td></tr><tr><td><strong>Department</strong><br>{{ $item->employee->department?->name ?? '-' }}</td><td><strong>Position</strong><br>{{ $item->employee->position?->title ?? '-' }}</td></tr><tr><td><strong>Pay period</strong><br>{{ $item->run->period_start->format('d M Y') }} – {{ $item->run->period_end->format('d M Y') }}</td><td><strong>Payment date</strong><br>{{ $item->run->payment_date->format('d M Y') }}</td></tr></table>
<table class="table"><thead><tr><th>Earnings</th><th class="amount">BDT</th><th>Deductions</th><th class="amount">BDT</th></tr></thead><tbody>@php($earnings=$item->earnings??[]) @php($deductions=$item->deductions??[]) @for($i=0;$i<max(count($earnings),count($deductions));$i++)<tr><td>{{ array_keys($earnings)[$i]??'' }}</td><td class="amount">{{ isset(array_values($earnings)[$i])?number_format(array_values($earnings)[$i],2):'' }}</td><td>{{ array_keys($deductions)[$i]??'' }}</td><td class="amount">{{ isset(array_values($deductions)[$i])?number_format(array_values($deductions)[$i],2):'' }}</td></tr>@endfor<tr class="total"><td>Gross earnings</td><td class="amount">{{ number_format($item->gross_earnings,2) }}</td><td>Total deductions</td><td class="amount">{{ number_format($item->gross_earnings-$item->net_pay,2) }}</td></tr><tr class="total"><td colspan="3">Net pay</td><td class="amount">{{ number_format($item->net_pay,2) }}</td></tr></tbody></table>
